class Solution(object):
    def distanceLimitedPathsExist(self, n, edges, queries):
        # Sort edges and queries, use Union-Find
        edges.sort(key=lambda x: x[2])
        queries = [(q[0], q[1], q[2], i) for i, q in enumerate(queries)]
        queries.sort(key=lambda x: x[2])

        parent = list(range(n))

        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            px, py = find(x), find(y)
            if px != py:
                parent[px] = py

        result = [False] * len(queries)
        edge_idx = 0

        for u, v, limit, q_idx in queries:
            while edge_idx < len(edges) and edges[edge_idx][2] < limit:
                a, b, _ = edges[edge_idx]
                union(a, b)
                edge_idx += 1

            result[q_idx] = find(u) == find(v)

        return result
